// Called at end of every workflow. Receives items from storage step.
const results = $input.all();
const ctx     = $('Set Workflow Context').first()?.json?._ctx ?? {};
const stored  = results.filter(r => r.json?.success === true).length;
const failed  = results.filter(r => r.json?.success === false).length;
const summary = {
  workflow:     ctx.workflow_name || 'unknown',
  source_slug:  ctx.source_slug   || 'unknown',
  run_id:       ctx.run_id        || `run_${Date.now()}`,
  started_at:   ctx.started_at,
  finished_at:  new Date().toISOString(),
  duration_ms:  ctx.started_at ? Date.now() - new Date(ctx.started_at).getTime() : 0,
  status:       failed > 0 ? 'partial' : 'success',
  items_stored: stored,
  items_failed: failed,
  items_total:  results.length,
};
console.log('[SUMMARY]', JSON.stringify(summary));
return [{ json: summary }];
